 59	  return (
 60	    <>
 61	      {actionState.map((element, index) => (
 62	        <span
 63	          key={actionType + index}
 64	          className="pf-v6-u-display-flex pf-v6-u-flex-direction-row pf-v6-u-mb-xs"
 65	        >
 66	          <TextInput
 67	            value={element}
 68	            onChange={(_e, value) => onChange(index, value)}
 69	            placeholder={placeholder}
 70	            className="pf-v6-u-mr-sm pf-v6-u-w-50"
 71	          />
 72	          <Button
 73	            variant={ButtonVariant.plain}
 74	            onClick={() =>
 75	              dispatch({
 76	                type: actionType,
 77	                payload: actionState.filter((_, i) => i !== index),
