101	export const CorsFormContents: React.FC<
102	  StateAndDispatchProps & {
103	    existingRules: GetBucketCorsCommandOutput;
104	    isEdit?: boolean;
105	    editingRuleName?: string;
106	  }
107	> = ({ state, dispatch, existingRules, isEdit, editingRuleName }) => {
108	  const { t } = useCustomTranslation();
109	
110	  const name = state.name;
111	  const [invalidName, emptyName, alreadyUsedName, exceedingLengthName] =
112	    state.triggerInlineValidations
113	      ? isInvalidName(state, existingRules, isEdit, editingRuleName)
