115	
116	  const allowAllOrigins = state.allowAllOrigins;
117	  const allowedOrigins = state.allowedOrigins;
118	  const invalidOrigin =
119	    state.triggerInlineValidations && isInvalidOrigin(state);
120	
121	  const allowedMethods = state.allowedMethods;
122	  const invalidMethod =
123	    state.triggerInlineValidations && isInvalidMethod(state);
124	
125	  const allowAllHeaders = state.allowAllHeaders;
126	  const allowedHeaders = state.allowedHeaders;
127	
128	  const exposedHeaders = state.exposedHeaders;
129	
130	  const maxAge = state.maxAge;
131	
132	  return (
133	    <>
134	      <FormGroup
135	        label={t('Rule name')}
136	        fieldId="name"
137	        className="pf-v6-u-mb-lg"
138	      >
139	        <TextInput
140	          id="name"
141	          value={name}
142	          onChange={(_e, value) =>
143	            dispatch({ type: RuleActionType.RULE_NAME, payload: value })
144	          }
145	          placeholder={t('Enter a valid rule name')}
146	          className="pf-v6-u-w-50"
147	          validated={
148	            invalidName ? ValidatedOptions.error : ValidatedOptions.default
149	          }
150	        />
151	        {invalidName && (
152	          <FormHelperText>
153	            <HelperText>
154	              <HelperTextItem variant={ValidatedOptions.error}>
155	                {emptyName && t('A rule name is required.')}
156	                {alreadyUsedName &&
157	                  t(
158	                    'A rule with this name already exists. Type a different name.'
159	                  )}
160	                {exceedingLengthName && t('No more than 255 characters')}
161	              </HelperTextItem>
162	            </HelperText>
163	          </FormHelperText>
164	        )}
165	      </FormGroup>
166	
167	      <FormGroup
168	        label={
169	          <>
170	            {t('Allowed origins')}
171	            <FieldLevelHelp>
172	              {t(
173	                'List of domains allowed to access the resources (can include wildcards).'
174	              )}
175	            </FieldLevelHelp>
176	          </>
177	        }
178	        fieldId="allowed-origins"
179	      >
180	        <span className="pf-v6-u-display-flex pf-v6-u-flex-direction-column">
181	          <Radio
182	            label={t('All origins')}
183	            description={
184	              <Trans t={t}>
185	                Allow requests from all domains using a wildcard (*). Use{' '}
186	                <b>
187	                  <i>custom origins</i>
188	                </b>{' '}
189	                if requests include credentials like cookies or HTTP
190	                authentication.
191	              </Trans>
192	            }
193	            name={ORIGINS_RADIO_GROUP}
194	            isChecked={allowAllOrigins}
195	            onChange={() => {
196	              dispatch({
197	                type: RuleActionType.RULE_ORIGINS,
198	                payload: [WILDCARD],
199	              });
200	              dispatch({
201	                type: RuleActionType.RULE_ALLOW_ALL_ORIGINS,
202	                payload: true,
203	              });
204	            }}
205	            id="allowed-origins-all"
206	            className="pf-v6-u-mb-sm"
207	          />
208	          <Radio
209	            label={t('Custom origins')}
210	            description={t('Allow requests only from specified domains.')}
211	            name={ORIGINS_RADIO_GROUP}
212	            isChecked={!allowAllOrigins}
213	            onChange={() => {
214	              dispatch({
215	                type: RuleActionType.RULE_ORIGINS,
216	                payload: [],
217	              });
218	              dispatch({
219	                type: RuleActionType.RULE_ALLOW_ALL_ORIGINS,
220	                payload: false,
221	              });
222	            }}
223	            id="allowed-origins-custom"
224	            className="pf-v6-u-mt-sm"
225	          />
226	        </span>
227	        {invalidOrigin && (
228	          <Alert
229	            variant={AlertVariant.danger}
