234	          />
235	        )}
236	        {!allowAllOrigins && (
237	          <FormGroup
238	            label={t('Origin')}
239	            fieldId="origins"
240	            className="s3-cors-input--margin"
241	          >
242	            <AddTextInput
243	              actionState={allowedOrigins}
244	              dispatch={dispatch}
245	              actionType={RuleActionType.RULE_ORIGINS}
246	              placeholder={'https://allowed-origin.com'}
247	              addButtonText={
248	                allowedOrigins.length > 0
249	                  ? t('Add another origin')
250	                  : t('Add origin')
