252	            />
253	          </FormGroup>
254	        )}
255	      </FormGroup>
256	
257	      <FormGroup
258	        label={
259	          <>
260	            {t('Allowed methods')}
261	            <FieldLevelHelp>
262	              {t('HTTP methods that are permitted for cross-origin requests.')}
