264	          </>
265	        }
266	        fieldId="allowed-methods"
267	        className="pf-v6-u-my-lg"
268	      >
269	        {invalidMethod && (
270	          <Alert
271	            variant={AlertVariant.danger}
272	            isInline
273	            isPlain
274	            title={t('A method is required.')}
275	            className="s3-cors-validation--font-weight"
276	          />
277	        )}
278	        <span className="pf-v6-u-display-flex pf-v6-u-flex-direction-row">
279	          {Object.keys(AllowedMethods).map(
280	            (allowedMethod: AllowedMethods, index: number) => (
281	              <Checkbox
282	                id={allowedMethod + index}
283	                label={allowedMethod}
284	                isChecked={allowedMethods.includes(allowedMethod)}
285	                onChange={(_e, checked) => {
