296	                      ),
297	                    });
298	                }}
299	                className="pf-v6-u-mr-md"
300	              />
301	            )
302	          )}
303	        </span>
304	      </FormGroup>
305	
306	      <FormGroup
307	        label={
308	          <>
309	            {t('Allowed headers')}
310	            <FieldLevelHelp>
311	              {t('Headers that can be sent by the client in the request.')}
312	            </FieldLevelHelp>
313	          </>
314	        }
315	        fieldId="allowed-headers"
316	      >
317	        <span className="pf-v6-u-display-flex pf-v6-u-flex-direction-column">
318	          <Radio
319	            label={t('All headers')}
320	            description={
321	              <Trans t={t}>
322	                Allows all headers using a wildcard (*). Use{' '}
323	                <b>
324	                  <i>custom headers</i>
325	                </b>{' '}
326	                if requests include credentials like cookies or authentication
327	                headers.
328	              </Trans>
329	            }
330	            name={HEADERS_RADIO_GROUP}
331	            isChecked={allowAllHeaders}
332	            onChange={() => {
333	              dispatch({
334	                type: RuleActionType.RULE_HEADERS,
335	                payload: [WILDCARD],
336	              });
337	              dispatch({
338	                type: RuleActionType.RULE_ALLOW_ALL_HEADERS,
339	                payload: true,
340	              });
341	            }}
342	            id="allowed-headers-all"
343	            className="pf-v6-u-mb-sm"
344	          />
345	          <Radio
346	            label={t('Custom headers')}
347	            description={t('Restrict access to only the headers you specify.')}
348	            name={HEADERS_RADIO_GROUP}
349	            isChecked={!allowAllHeaders}
350	            onChange={() => {
351	              dispatch({
352	                type: RuleActionType.RULE_HEADERS,
353	                payload: [],
354	              });
355	              dispatch({
356	                type: RuleActionType.RULE_ALLOW_ALL_HEADERS,
357	                payload: false,
358	              });
359	            }}
360	            id="allowed-headers-custom"
361	            className="pf-v6-u-mt-sm"
362	          />
363	        </span>
364	        {!allowAllHeaders && (
365	          <FormGroup
366	            label={t('Header')}
367	            fieldId="headers"
368	            className="s3-cors-input--margin"
369	          >
370	            <AddTextInput
371	              actionState={allowedHeaders}
372	              dispatch={dispatch}
373	              actionType={RuleActionType.RULE_HEADERS}
374	              placeholder={t('Enter a header')}
375	              addButtonText={
376	                allowedHeaders.length > 0
377	                  ? t('Add another header')
378	                  : t('Add header')
379	              }
380	            />
381	          </FormGroup>
382	        )}
383	      </FormGroup>
384	
385	      <FormGroup
386	        label={
387	          <>
388	            {t('Exposed headers')}
389	            <FieldLevelHelp>
390	              {t('Headers that should be exposed to the browser.')}
391	            </FieldLevelHelp>
392	          </>
393	        }
394	        fieldId="exposed-headers"
395	        className="pf-v6-u-my-lg"
396	      >
397	        <AddTextInput
398	          actionState={exposedHeaders}
399	          dispatch={dispatch}
400	          actionType={RuleActionType.RULE_EXPOSED_HEADERS}
401	          placeholder={t('Enter an exposed header')}
402	          addButtonText={
403	            exposedHeaders.length > 0
404	              ? t('Add another header')
405	              : t('Add header')
406	          }
407	        />
408	      </FormGroup>
409	
410	      <FormGroup
411	        label={
412	          <>
413	            {t('Max age for preflight requests (in seconds)')}
414	            <FieldLevelHelp>
415	              {t(
416	                'Time in seconds for how long the browser should cache the CORS preflight response.'
417	              )}
418	            </FieldLevelHelp>
419	          </>
420	        }
421	        fieldId="max-preflight"
422	      >
423	        <NumberInput
424	          value={maxAge}
425	          onMinus={() =>
426	            dispatch({
427	              type: RuleActionType.RULE_MAX_AGE,
428	              payload: maxAge - 1 || 0,
429	            })
430	          }
431	          onPlus={() =>
432	            dispatch({
433	              type: RuleActionType.RULE_MAX_AGE,
434	              payload: maxAge + 1 || 0,
435	            })
436	          }
437	          onChange={(event) =>
438	            dispatch({
439	              type: RuleActionType.RULE_MAX_AGE,
440	              payload: +(event?.target as HTMLInputElement)?.value || 0,
441	            })
442	          }
443	        />
444	      </FormGroup>
445	    </>
446	  );
447	};

